={{
  (() => {
    // =====================================================================
    // 1. HELPER FUNCTIONS
    // =====================================================================

    function removeAccents(str) {
      if (!str) return "";
      return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim();
    }

    function generateMatchClauses(keyword, targetFields) {
        const rawKey = keyword.trim();
        if (!rawKey) return [];
        const variants = [...new Set([rawKey, rawKey.toLowerCase(), removeAccents(rawKey), removeAccents(rawKey).toLowerCase()])];
        const conditions = [];
        targetFields.forEach(field => {
            variants.forEach(v => {
                conditions.push({ "key": field, "match": { "text": v } });
            });
        });
        return conditions;
    }

    function processLogicFilter(textArray, fields, targetMustArray) {
        if (!textArray) return;
        const items = Array.isArray(textArray) ? textArray : [textArray];
        items.forEach(item => {
            if (!item || String(item).length > 150) return;
            if (item.match(/\s+(?:hoặc|or)\s+/i)) {
                const parts = item.split(/\s+(?:hoặc|or)\s+/i);
                let aggregatedShoulds = [];
                parts.forEach(part => { aggregatedShoulds.push(...generateMatchClauses(part, fields)); });
                if (aggregatedShoulds.length > 0) targetMustArray.push({ "should": aggregatedShoulds });
            } else {
                const parts = item.split(/\s*(?:và|and|,)\s*/i);
                parts.forEach(part => {
                    if(part.trim()) {
                        const clauses = generateMatchClauses(part, fields);
                        if (clauses.length > 0) targetMustArray.push({ "should": clauses });
                    }
                });
            }
        });
    }

    // =====================================================================
    // 2. MAIN LOGIC
    // =====================================================================

    // A. Vector
    let vector = $json.query_vector || $json.vector;
    if (!vector || vector.length === 0) { vector = new Array(1536).fill(0); }

    // B. AI Input
    let aiJson = {};
    try {
        const rawSource = $('message refined').item.json; 
        aiJson = rawSource.parsed_json || rawSource.output || {};
        if (typeof aiJson === 'string') { try { aiJson = JSON.parse(aiJson); } catch(e) {} }
    } catch (e) { aiJson = {}; }

    let mustConditions = [];

    // [CẤU HÌNH] Unified Fields
    const unifiedFields = ["text", "skills_list", "role", "company", "school", "major"];

    // ---------------------------------------------------------------------
    // [STRICT MODE] SO SÁNH TRỰC TIẾP VỚI INDEX (VÌ DATA KHÔNG NULL)
    // ---------------------------------------------------------------------
    if (aiJson.filter_experience) {
        const expStr = String(aiJson.filter_experience).trim();

        // Cải thiện Regex:
        // 1. Bắt dấu toán học: > 3, < 2.5
        const mathMatch = expStr.match(/^([<>=]+)\s*(\d+(?:[.,]\d+)?)$/);
        // 2. Bắt số thuần: "3", "3.5"
        const numberOnlyMatch = expStr.match(/^(\d+(?:[.,]\d+)?)$/);

        let rangeQuery = null;

        if (mathMatch) {
            const operator = mathMatch[1];
            const number = parseFloat(mathMatch[2].replace(',', '.'));

            if (operator.includes('>')) {
                 // Nếu >= dùng gte, nếu > dùng gt
                 rangeQuery = operator.includes('=') ? { "gte": number } : { "gt": number };
            } else if (operator.includes('<')) {
                 // Nếu <= dùng lte, nếu < dùng lt
                 rangeQuery = operator.includes('=') ? { "lte": number } : { "lt": number };
            } else if (operator.includes('=')) {
                 // Bằng chính xác
                 rangeQuery = { "gte": number, "lte": number };
            }
        } 
        else if (numberOnlyMatch) {
            const number = parseFloat(numberOnlyMatch[1].replace(',', '.'));
            // Mặc định: Nếu chỉ nói "3 năm", ta hiểu là "tối thiểu 3 năm" (>= 3)
            rangeQuery = { "gte": number };
        }

        // Áp dụng Filter cứng (VÌ DATA ĐÃ SẠCH)
        if (rangeQuery) {
             mustConditions.push({ "key": "experience_years", "range": rangeQuery });
        }
    }
    // ---------------------------------------------------------------------

    // Xử lý Skill
    if (aiJson.filter_skills) {
        const skills = Array.isArray(aiJson.filter_skills) ? aiJson.filter_skills : [aiJson.filter_skills];
        processLogicFilter(skills, unifiedFields, mustConditions);
    }

    // Xử lý Company
    if (aiJson.filter_company) {
        const companies = Array.isArray(aiJson.filter_company) ? aiJson.filter_company : [aiJson.filter_company];
        processLogicFilter(companies, ["company", "text"], mustConditions);
    }

    // Output
    // Threshold có thể để cao hơn một chút vì data sạch, filter chính xác
    let smartThreshold = (mustConditions.length > 0) ? 0.55 : 0.75; 
    if ($json.score_threshold !== undefined) smartThreshold = $json.score_threshold;

    let body = {
      "vector": vector,
      "limit": 50, 
      "with_payload": true,
      "score_threshold": smartThreshold,
      "group_by": "candidate_id", 
      "group_size": 1 
    };

    if (mustConditions.length > 0) {
      body.filter = { "must": mustConditions };
    }

    return JSON.stringify(body);
  })()
}}
